from __future__ import annotations

import os
import re
from dataclasses import dataclass
from urllib.parse import urlparse

_IMAGE_DIGEST_RE = re.compile(r"@sha256:[a-f0-9]{64}$")


@dataclass(frozen=True, slots=True)
class DevpodSettings:
    devpod_workspace_image: str
    devpod_provider: str
    devpod_up_timeout_s: int
    ssh_verify_timeout_s: int


@dataclass(frozen=True, slots=True)
class WebTerminalSettings:
    ngrok_authtoken: str
    ngrok_reserved_domains: tuple[str, ...]
    terminal_public_port: int
    ssh_bash_timeout_s: int


def _require_env(name: str) -> str:
    value = os.environ.get(name, "").strip()
    if not value:
        raise ValueError(f"Missing required environment variable: {name}")
    return value


def _require_positive_int(name: str) -> int:
    raw = _require_env(name)
    try:
        value = int(raw)
    except ValueError as exc:
        raise ValueError(f"{name} must be a positive integer, got: {raw!r}") from exc
    if value <= 0:
        raise ValueError(f"{name} must be a positive integer, got: {value}")
    return value


def _validate_workspace_image(image: str) -> str:
    if not _IMAGE_DIGEST_RE.search(image):
        raise ValueError(
            "REBASE_DEVPOD_WORKSPACE_IMAGE must include a digest suffix "
            "matching @sha256:<64 lowercase hex chars>"
        )
    return image


def load_devpod_settings() -> DevpodSettings:
    image = _validate_workspace_image(_require_env("REBASE_DEVPOD_WORKSPACE_IMAGE"))
    provider = os.environ.get("DEVPOD_PROVIDER", "rebase").strip() or "rebase"
    return DevpodSettings(
        devpod_workspace_image=image,
        devpod_provider=provider,
        devpod_up_timeout_s=_require_positive_int("DEVPOD_UP_TIMEOUT_SECONDS"),
        ssh_verify_timeout_s=_require_positive_int("PROVISION_SSH_VERIFY_TIMEOUT_SECONDS"),
    )


def load_web_terminal_settings() -> WebTerminalSettings:
    domains_raw = os.environ.get("NGROK_RESERVED_DOMAINS", "").strip()
    domains = tuple(d.strip() for d in domains_raw.split(",") if d.strip())
    port_raw = os.environ.get("TERMINAL_PUBLIC_PORT", "7681").strip()
    try:
        port = int(port_raw)
    except ValueError as exc:
        raise ValueError(f"TERMINAL_PUBLIC_PORT must be an integer, got: {port_raw!r}") from exc
    if port <= 0 or port > 65535:
        raise ValueError(f"TERMINAL_PUBLIC_PORT must be 1-65535, got: {port}")
    return WebTerminalSettings(
        ngrok_authtoken=_require_env("NGROK_AUTHTOKEN"),
        ngrok_reserved_domains=domains,
        terminal_public_port=port,
        ssh_bash_timeout_s=_require_positive_int("WEB_TERMINAL_SSH_TIMEOUT_SECONDS"),
    )


def validate_supabase_management_url(url: str) -> str:
    parsed = urlparse(url)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc:
        raise ValueError("SUPABASE_MANAGEMENT_API_URL must be an http(s) URL with a host")
    return url.rstrip("/")

