"""Supabase Management API client for provisioner bootstrap."""

from __future__ import annotations

import json
from dataclasses import dataclass
from typing import Protocol
from urllib.parse import urljoin

import httpx

from agents.devpod.stream_tails import stream_tail


@dataclass(frozen=True, slots=True)
class SupabaseProjectRef:
    project_ref: str
    api_url: str


class SupabaseManagementClient(Protocol):
    async def create_project(self, *, name: str, organization_id: str) -> SupabaseProjectRef: ...


@dataclass(frozen=True, slots=True)
class HttpxSupabaseManagementClient:
    api_base_url: str
    access_token: str
    default_region: str

    async def create_project(self, *, name: str, organization_id: str) -> SupabaseProjectRef:
        url = urljoin(self.api_base_url.rstrip("/") + "/", "projects")
        headers = {
            "Authorization": f"Bearer {self.access_token}",
            "Content-Type": "application/json",
        }
        body = {
            "name": name,
            "organization_id": organization_id,
            "region": self.default_region,
            "plan": "free",
        }
        timeout = httpx.Timeout(connect=30.0, read=120.0, write=30.0, pool=30.0)
        async with httpx.AsyncClient(timeout=timeout) as client:
            response = await client.post(url, headers=headers, json=body)
            if response.status_code >= 400:
                tail = stream_tail(response.text)
                raise SupabaseManagementError(
                    status_code=response.status_code,
                    body_tail=tail,
                )
            data = response.json()
        project_ref = str(data.get("id") or data.get("ref") or "").strip()
        if not project_ref:
            raise SupabaseManagementError(
                status_code=response.status_code,
                body_tail="create project response missing id/ref",
            )
        api_url = str(data.get("api_url") or f"https://{project_ref}.supabase.co").strip()
        return SupabaseProjectRef(project_ref=project_ref, api_url=api_url)


@dataclass(frozen=True, slots=True)
class SupabaseManagementError(Exception):
    status_code: int
    body_tail: str

    def __str__(self) -> str:
        return f"Supabase Management API error {self.status_code}: {self.body_tail}"

