RenderTileEvent = RunOutputEvent

_provisioner_progress_queue_ctx: contextvars.ContextVar[ProgressQueue | None] = (
    contextvars.ContextVar(
        "provisioner_progress_queue",
        default=None,
    )
)


@dataclass
class PipelineProgressState:
    steps: list[ProvisionPipelineStep] = field(
        default_factory=lambda: [
            {"id": "dev_infra", "status": "pending"},
            {"id": "terminal_bootstrap", "status": "pending"},
        ]
    )
    current_milestone: ProvisionMilestoneKind = "DevInfraStarted"
    milestone_detail: str | None = None
    terminal_url: str | None = None

    def props(self) -> ProvisionPipelineCardProps:
        props: ProvisionPipelineCardProps = {
            "steps": self.steps,
            "currentMilestone": self.current_milestone,
        }
        if self.milestone_detail is not None:
            props["milestoneDetail"] = self.milestone_detail[:200]
        if self.terminal_url is not None:
            props["terminalUrl"] = self.terminal_url
        return props


class ProgressQueue:
    """In-memory queue of pending render tile events for one agent run."""

    def __init__(self) -> None:
        self._queue: asyncio.Queue[RenderTileEvent] = asyncio.Queue()

    async def put_tile_events(
        self, *, run_meta: dict[str, Any], props: ProvisionPipelineCardProps
    ) -> None:
        for event in build_pipeline_tile_events(run_meta=run_meta, props=props):
            await self._queue.put(event)

    async def get(self) -> RenderTileEvent:
        return await self._queue.get()

    def empty(self) -> bool:
        return self._queue.empty()


def bind_progress_queue(queue: ProgressQueue) -> contextvars.Token[ProgressQueue | None]:
    return _provisioner_progress_queue_ctx.set(queue)


def reset_progress_queue(token: contextvars.Token[ProgressQueue | None]) -> None:
    _provisioner_progress_queue_ctx.reset(token)


def progress_queue_for_run(run_context: Any) -> ProgressQueue | None:
    """Resolve the per-run queue from contextvar or run dependencies."""
    queue = _provisioner_progress_queue_ctx.get()
    if isinstance(queue, ProgressQueue):
        return queue
    dependencies = getattr(run_context, "dependencies", None)
    if isinstance(dependencies, dict):
        from_deps = dependencies.get(PROGRESS_QUEUE_DEP_KEY)
        if isinstance(from_deps, ProgressQueue):
            return from_deps
    return None


def build_pipeline_tile_events(
    *,
    run_meta: dict[str, str],
    props: ProvisionPipelineCardProps,
) -> list[RenderTileEvent]:
    tool_call_id = str(uuid.uuid4())
    result = render_provision_pipeline_card.entrypoint(**props)  # type: ignore[misc]
    tool = ToolExecution(
        tool_call_id=tool_call_id,
        tool_name=RENDER_PROVISION_PIPELINE_CARD,
        tool_args=dict(props),
        result=json.dumps(result),
    )
    return [
        ToolCallStartedEvent(
            tool=tool,
            agent_id=run_meta["agent_id"],
            agent_name=run_meta["agent_name"],
            run_id=run_meta["run_id"],
            session_id=run_meta["session_id"],
        ),
        ToolCallCompletedEvent(
            tool=tool,
            content=result,
            agent_id=run_meta["agent_id"],
            agent_name=run_meta["agent_name"],
            run_id=run_meta["run_id"],
            session_id=run_meta["session_id"],
        ),
    ]


def run_meta_from_context(run_context: Any) -> dict[str, str]:
    return {
        "run_id": run_context.run_id,
        "session_id": run_context.session_id,
        "agent_id": str(getattr(run_context, "agent_id", "") or ""),
        "agent_name": str(getattr(run_context, "agent_name", "") or ""),
    }

